                  <input type="text" id="jk_department" placeholder="Metro Police Department">
                </div>
              </div>
              <div class="jkit__row">
                <div class="jkit__field">
                  <label>Supervisor Name *</label>
                  <input type="text" id="jk_supervisor" placeholder="Captain Johnson">
                </div>
                <div class="jkit__field">
                  <label>Supervisor Title</label>
                  <input type="text" id="jk_sup_title" placeholder="Captain">
                </div>
              </div>
              <div class="jkit__field">
                <label>Additional Context <span style="font-weight:400;text-transform:none;letter-spacing:0;">(optional)</span></label>
                <textarea id="jk_context" placeholder="e.g. We have 3 pending crash cases with aerial evidence needs, our training budget resets in July..."></textarea>
                <div class="jkit__context-note">Anything that helps make the case — pending cases, budget timing, prior UAS program gaps.</div>
              </div>
              <button class="jkit__generate-btn" id="jk_btn">
                <span id="jk_btn_label" style="display:flex;align-items:center;gap:10px;">
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline><line x1="16" y1="13" x2="8" y2="13"></line><line x1="16" y1="17" x2="8" y2="17"></line><polyline points="10 9 9 9 8 9"></polyline></svg>
                  Generate My Letter
                </span>
                <span id="jk_btn_loading" style="display:none;align-items:center;gap:10px;">
                  <div class="spinner"></div>
                  Writing your letter...
                </span>
              </button>
            </div>
            <div class="jkit__output-wrap" id="jk_output_wrap">
              <div style="padding: 0 28px;"><div class="jkit__output-divider"></div></div>
              <div style="padding: 0 28px 28px;">
                <div class="jkit__output-actions">
                  <div class="jkit__output-label">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline></svg>
                    Letter Ready
                  </div>
                  <div class="jkit__action-btns">
                    <button class="jkit__btn-sm jkit__btn-copy" id="jk_copy_btn">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="width:13px;height:13px;"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
                      Copy
                    </button>
                    <button class="jkit__btn-sm jkit__btn-word" id="jk_download_btn">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="width:13px;height:13px;"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path><polyline points="14 2 14 8 20 8"></polyline></svg>
                      Download Word
                    </button>
                  </div>
                </div>
                <div class="jkit__letter-output" id="jk_letter_output"></div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <!-- ── FINAL CTA ────────────────────────────────── -->
      <section class="final-cta">
        <div class="final-cta__content">
          <h2 class="final-cta__title">Stop Producing <span>Aerial Photographs.</span></h2>
          <p class="final-cta__text">Four days and you walk out with a finished workflow, court-ready software, and a diagram from your own flight. Registration is open for the sessions above — pick your date.</p>
          <a href="#sessions" class="final-cta__btn">
            View Upcoming Sessions
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>
          </a>
        </div>
      </section>

      <!-- ── FAQ ─────────────────────────────────────── -->
      <section class="section section--dark">
        <div class="container">
          <div class="section-header">
            <div class="section-eyebrow">Common Questions</div>
            <h2 class="section-title">Frequently <span>Asked</span></h2>
          </div>
          <div class="faq-list">

            <div class="faq-item">
              <button class="faq-item__question">
                Do I need a Part 107 to attend?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">Yes, or you need to be actively working toward it. FDM is a mapping and diagramming course — we assume you can already legally fly. If you need Part 107, check out READY 107, our FAA test prep course built specifically for law enforcement. The two courses stack naturally.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                What software is included and what computer do I need?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">Every registration includes 1-year access to photogrammetric processing and professional CAD diagramming software. Photogrammetric processing is computationally intensive — you'll want a modern laptop with a dedicated GPU, 16GB+ RAM, and an SSD. A detailed hardware recommendation is included in your enrollment confirmation.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                What drone do I need to bring?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">Any capable mapping drone — agency-owned, personal, or borrowed. DJI Phantom 4, Mavic 3 Enterprise, Matrice series, and similar platforms all work. RTK-capable drones simplify the GCP workflow but are not required. The course teaches methods that work with and without RTK hardware.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                Is lodging or travel assistance available?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">We don't book lodging, but we provide a recommended hotels list near each training site with every registration confirmation. Many agencies use this course to fulfill training budget requirements and cover travel and per diem — we can provide the documentation your finance or admin team needs to process reimbursement.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                Can my agency send multiple attendees?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">Absolutely — register as many seats as you need at the flat per-student rate. If your agency wants to host a private FDM session for a larger group, contact us about bringing the course to you. We can work with your scheduling, facility, and budget requirements directly.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                What does the Agency Usage Guarantee cover?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">If an officer your agency enrolled in the course separates from the department within two years of their attendance date — for any reason — we'll enroll a replacement at no charge, up to one time per original seat. Your training investment stays with the agency, not the individual who walks out the door.</div>
              </div>
            </div>

            <div class="faq-item">
              <button class="faq-item__question">
                What if I need to cancel my registration?
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
              </button>
              <div class="faq-item__answer">
                <div class="faq-item__answer-inner">Cancellations made 30 or more days before the course start date receive a full refund minus a 3% processing fee. Cancellations within 30 days can transfer their seat to a colleague at no charge, or apply the registration credit toward a future FDM session. Contact us and we'll work something out — we understand that law enforcement schedules change.</div>
              </div>
            </div>

          </div>
        </div>
      </section>
    `;

    // ── API CONSTANTS ─────────────────────────────────────────────
    const PROXY_URL    = 'https://training.trafficcoplabs.com/api/generate-letter/';
    const CRM_URL      = 'https://crm.trafficcoplabs.com/api/letter-lead/';
    const PRODUCTS_URL = 'https://crm.trafficcoplabs.com/api/products/';
    const EVENTS_URL   = 'https://crm.trafficcoplabs.com/api/events/';

    let generatedLetter = '';
    let productsData = { courses: [], software: [] };

    // Load products and find FDM course
    async function loadProducts() {
      try {
        const res = await fetch(PRODUCTS_URL);
        productsData = await res.json();

        // Find FDM course
        const fdmCourse = (productsData.courses || []).find(c =>
          c.name.toLowerCase().includes('fdm') || 
          c.name.toLowerCase().includes('fundamentals') ||
          c.name.toLowerCase().includes('drone mapping')
        );

        if (fdmCourse) {
          // Load events for this course
          await loadEventsForCourse(fdmCourse.id);
        }
      } catch (error) {
        console.error('Failed to load products:', error);
      }
    }

    async function loadEventsForCourse(courseId) {
      try {
        const res = await fetch(`${EVENTS_URL}?product_id=${courseId}`);
        const data = await res.json();

        // Update the dropdown with real events
        const eventSelect = shadow.getElementById('jk_event');
        eventSelect.innerHTML = '';

        (data.events || []).forEach(e => {
          let label = e.name;
          if (e.date) label += ` — ${e.date}`;
          if (e.location && e.delivery !== 'online') label += ` (${e.location})`;
          if (e.status === 'full') label += ' [FULL]';
          eventSelect.innerHTML += `<option value="${e.id}">${label}</option>`;
        });

        // Add fallback option if no events
        if (!data.events || data.events.length === 0) {
          eventSelect.innerHTML = '<option value="online">Online / Self-Paced</option>';
        }

      } catch (error) {
        console.error('Failed to load events:', error);
        // Keep the existing hardcoded option as fallback
      }
    }

    // Start loading products immediately
    loadProducts();

    // ── LETTER GENERATION ─────────────────────────────────────────
    async function generateJustificationLetter() {
      const name       = shadow.getElementById('jk_name').value.trim();
      const email      = shadow.getElementById('jk_email').value.trim();
      const department = shadow.getElementById('jk_department').value.trim();
      const supervisor = shadow.getElementById('jk_supervisor').value.trim();

      if (!name || !email || !department || !supervisor) {
        alert('Please fill in your name, email, department, and supervisor name.');
        return;
      }

      const btn = shadow.getElementById('jk_btn');
      btn.disabled = true;
      shadow.getElementById('jk_btn_label').style.display = 'none';
      shadow.getElementById('jk_btn_loading').style.display = 'flex';

      // Get the actual product ID and event ID (like test page)
      let productId = '', eventId = 'online', productName = '';

      // Find FDM course
      const fdmCourse = (productsData.courses || []).find(c =>
        c.name.toLowerCase().includes('fdm') || 
        c.name.toLowerCase().includes('fundamentals') ||
        c.name.toLowerCase().includes('drone mapping')
      );

      if (fdmCourse) {
        productId = fdmCourse.id;
        productName = fdmCourse.name;
      }

      // Get selected event ID
      const eventSelect = shadow.getElementById('jk_event');
      if (eventSelect && eventSelect.value) {
        eventId = eventSelect.value;
      }

      const payload = {
        name, email, department,
        rank: shadow.getElementById('jk_rank').value.trim(),
        supervisor_name: supervisor,
        supervisor_title: shadow.getElementById('jk_sup_title').value.trim(),
        letter_type: 'training',
        product_id: productId,
        event_id: eventId,
        hardware_description: '',
        additional_context: shadow.getElementById('jk_context').value.trim(),
      };

      try {
        const res  = await fetch(PROXY_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        const data = await res.json();
        if (data.letter) {
          generatedLetter = data.letter;
          shadow.getElementById('jk_letter_output').textContent = data.letter;
          shadow.getElementById('jk_output_wrap').classList.add('visible');
          shadow.getElementById('jk_output_wrap').scrollIntoView({ behavior: 'smooth', block: 'nearest' });

          // CRM lead capture — include the generated letter (like test page)
          fetch(CRM_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ ...payload, product_name: productName, generated_letter: data.letter })
          }).catch(() => {});
        } else {
          alert('Error: ' + (data.error || 'Unknown error'));
        }
      } catch (err) {
        alert('Failed to reach the server. Please try again.');
      } finally {
        btn.disabled = false;
        shadow.getElementById('jk_btn_label').style.display = 'flex';
        shadow.getElementById('jk_btn_loading').style.display = 'none';
      }
    }

    function copyJustificationLetter() {
      navigator.clipboard.writeText(generatedLetter).then(() => {
        const btn = shadow.getElementById('jk_copy_btn');
        const orig = btn.innerHTML;
        btn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="width:13px;height:13px;"><polyline points="20 6 9 17 4 12"></polyline></svg> Copied!';
        setTimeout(() => { btn.innerHTML = orig; }, 2000);
      });
    }

    async function downloadJustificationDocx() {
      if (!generatedLetter) {
        alert('Please generate a letter first.');
        return;
      }

      const btn = shadow.getElementById('jk_download_btn');
      const origHTML = btn.innerHTML;

      try {
        // Show loading state
        btn.disabled = true;
        btn.innerHTML = '<div style="width:13px;height:13px;border:2px solid rgba(0,0,0,0.3);border-top-color:#000;border-radius:50%;animation:spin 0.7s linear infinite;"></div> Creating...';

        // Use server-side Word generation (like your test file)
        const response = await fetch('https://training.trafficcoplabs.com/api/letter-to-docx/', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ letter: generatedLetter })
        });

        if (response.ok) {
          const blob = await response.blob();
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = 'fdm-justification-letter.docx';
          link.click();
          URL.revokeObjectURL(url);

          // Show success
          btn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="width:13px;height:13px;"><polyline points="20 6 9 17 4 12"></polyline></svg> Downloaded!';
          setTimeout(() => {
            btn.innerHTML = origHTML;
            btn.disabled = false;
          }, 2000);
        } else {
          throw new Error('Server failed to generate Word document');
        }

      } catch (error) {
        console.error('Word download error:', error);

        btn.innerHTML = origHTML;
        btn.disabled = false;

        // Fallback to copy
        if (confirm('Word download failed. Would you like to copy the letter text instead?')) {
          copyJustificationLetter();
        }
      }
    }

    shadow.getElementById('jk_btn').addEventListener('click', generateJustificationLetter);
    shadow.getElementById('jk_copy_btn').addEventListener('click', copyJustificationLetter);
    shadow.getElementById('jk_download_btn').addEventListener('click', downloadJustificationDocx);

    // ANCHOR NAVIGATION — hash links inside Shadow DOM
    shadow.querySelectorAll('a[href^="#"]').forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const targetId = link.getAttribute('href').substring(1);
        const target = shadow.getElementById(targetId);
        if (target) {
          const rect = target.getBoundingClientRect();
          window.scrollTo({ top: window.scrollY + rect.top, behavior: 'smooth' });
        }
      });
    });

    // MODULE ACCORDION
    const modules = shadow.querySelectorAll('.module');
    modules.forEach(mod => {
      const header = mod.querySelector('.module__header');
      const body = mod.querySelector('.module__body');
      header.addEventListener('click', () => {
        const isOpen = mod.classList.contains('is-open');
        modules.forEach(m => {
          m.classList.remove('is-open');
          m.querySelector('.module__body').style.maxHeight = '0';
        });
        if (!isOpen) {
          mod.classList.add('is-open');
          body.style.maxHeight = body.scrollHeight + 'px';
        }
      });
    });

    // FAQ ACCORDION
    const faqs = shadow.querySelectorAll('.faq-item');
    faqs.forEach(faq => {
      const question = faq.querySelector('.faq-item__question');
      const answer = faq.querySelector('.faq-item__answer');
      question.addEventListener('click', () => {
        const isOpen = faq.classList.contains('is-open');
        faqs.forEach(f => {
          f.classList.remove('is-open');
          f.querySelector('.faq-item__answer').style.maxHeight = '0';
        });
        if (!isOpen) {
          faq.classList.add('is-open');
          answer.style.maxHeight = answer.scrollHeight + 'px';
        }
      });
    });
  }
}

customElements.define('tcl-fdm-inperson-page', TCLFdmInpersonPage);
</script>
